package poolregistry

import (
	"encoding/hex"

	"github.com/ethereum/go-ethereum/accounts/abi"
)

// poolCreationCodeHex is the compiled creation (deployment) bytecode of Pool.sol.
//
// Produced by:
//
//	solc pool/Pool.sol --bin --optimize --optimize-runs 200 \
//	  --metadata-hash none --base-path .
//
// with solc 0.8.34. The metadata IPFS hash is stripped (--metadata-hash none)
// so the bytes don't shift with source comments or file paths; only the trailing
// solc-version tag remains.
//
// IMPORTANT: changing this byte sequence changes every pool's deterministic
// CREATE2 address, so any keeper state written under the old bytecode becomes
// orphaned. Recompile and replace only deliberately, and migrate state if you do.
const poolCreationCodeHex = ""

// PoolBytecode is the compiled deployment bytecode of Pool.sol, decoded from
// poolCreationCodeHex. RegisterDemandForView deploys this via CREATE2 and
// derivePoolAddress predicts the resulting address from the same bytes, so the
// keeper-recorded pool address always matches the on-chain contract.
var PoolBytecode = mustDecodeHex(poolCreationCodeHex)

// PoolConstructorArgs packs (viewAddress) for Pool's constructor.
// The pool's configuration is not stored on the contract — callers fetch it
// from PoolRegistry.getPoolDetail via Pool.snapshot().
var PoolConstructorArgs = abi.Arguments{
	{Type: mustABIType("address")},
}

func mustDecodeHex(s string) []byte {
	b, err := hex.DecodeString(s)
	if err != nil {
		panic("poolregistry: invalid Pool bytecode hex: " + err.Error())
	}
	return b
}
